import DataLoader from 'dataloader';
import sift from 'sift';
// the only line to delete once we are ready to use real data
import summaries from '../fixtures/workerTypeSummaries';

export default ({ workerManager }) => {
  const WorkerManagerWorkerTypeSummaries = new DataLoader(queries =>
    Promise.all(
      queries.map(async (filter) => {
        // const summaries = await workerManager.listWorkerTypes();
  
        return filter ? sift(filter, summaries) : summaries;
      })
    )
  );

  return {
    WorkerManagerWorkerTypeSummaries,
  };
};
```

Another thing is that as long as there's content inside the `fixtures` directory, we'll know that there's still some cleanup work to be done.

I don't particularly mind forcing the more verbose function syntax. Referencing functions by string value seems unnecessarily magical and [isn't covered in the Vue intro guide](https://vuejs.org/v2/guide/computed.html).

Opaque without knowledge of Vue:

```javascript
    watch: {
      username: 'setSuggestionTerm',
    }
```

Very explicit and readable:

```javascript
    watch: {
      username() {
        this.setSuggestionTerm();
      },
    }
```

Concise and explicit, but maybe less readable:

```javascript
    watch: {
      username: () => this.setSuggestionTerm(),
    }
```

I agree that format is common elsewhere, but I am following the pattern in this file. See, for example: https://github.com/dagster-io/dagster/blob/master/python_modules/dagster/dagster/_core/execution/context/compute.py#L171-L192:
 ```python
    @public
    @property
    def resources(self) -> Any:
        """Resources: The currently available resources."""
        return self._step_execution_context.resources

    @property
    def step_launcher(self) -> Optional[StepLauncher]:
        """Optional[StepLauncher]: The current step launcher, if any."""
        return self._step_execution_context.step_launcher

    @public
    @property
    def run_id(self) -> str:
        """str: The id of the current execution's run."""
        return self._step_execution_context.run_id

    @public
    @property
    def run_config(self) -> Mapping[str, object]:
        """dict: The run config for the current execution."""
        return self._step_execution_context.run_config
```

Note that this abbreviated format is the one that the `napoleon` Sphinx extension (which dagster uses) seems to recommend for public properties (https://sphinxcontrib-napoleon.readthedocs.io/en/latest/example_google.html). Just to say one is not necessarily better than the other - but I'm happy to change it to be consistent.

Would you like me to bring the rest of the docstrings in this file in line with that format, with a `Returns` key? Or just the ones that I've written?

